import React, { useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import styled from 'styled-components';
import { useTranslation } from 'react-i18next';

// Components
import ProductCard from '../components/ProductCard';
import Loading from '../components/Loading';
import Error from '../components/Error';

// Hooks
import useFetch from '../hooks/useFetch';

// API
import { getStoreDiscounts } from '../utils/api';

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 1.5rem;
`;

const BackLink = styled(Link)`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  color: ${({ theme }) => theme.colors.primary};
  font-weight: 500;
  margin-bottom: 1rem;

  &:hover {
    text-decoration: underline;
  }
`;

const StoreHeader = styled.div`
  margin-bottom: 2rem;
`;

const StoreName = styled.h1`
  font-size: ${({ theme }) => theme.fontSizes['2xl']};
  font-weight: 700;
  margin-bottom: 0.5rem;
  color: ${({ theme }) => theme.colors.text};
`;

const StoreLocation = styled.p`
  font-size: ${({ theme }) => theme.fontSizes.md};
  color: ${({ theme }) => theme.colors.textLight};
`;

const SectionTitle = styled.h2`
  font-size: ${({ theme }) => theme.fontSizes.xl};
  font-weight: 600;
  margin-bottom: 1.5rem;
  color: ${({ theme }) => theme.colors.text};
`;

const Grid = styled.div`
  display: grid;
  grid-template-columns: repeat(1, 1fr);
  gap: 1.5rem;

  @media (min-width: ${({ theme }) => theme.breakpoints.sm}) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (min-width: ${({ theme }) => theme.breakpoints.lg}) {
    grid-template-columns: repeat(3, 1fr);
  }
`;

const EmptyState = styled.div`
  text-align: center;
  padding: 3rem 1rem;
  color: ${({ theme }) => theme.colors.textLight};
`;

const StoreDetail = () => {
  const { storeId } = useParams();
  const { t } = useTranslation();

  const fetchStoreDiscounts = async () => {
    try {
      console.log(`Fetching store discounts for ID: ${storeId}`);
      const result = await getStoreDiscounts(storeId);
      console.log('Store discounts result:', result);
      return result;
    } catch (error) {
      console.error('Error in fetchStoreDiscounts:', error);
      throw error;
    }
  };

  const { data, loading, error, refetch } = useFetch(fetchStoreDiscounts, [storeId]);

  useEffect(() => {
    console.log('StoreDetail data:', data);
  }, [data]);

  const store = data?.store;
  const discounts = data?.discounts || [];

  return (
    <Container>
      <BackLink to="/">
        ŌåÉ {t('backToStores')}
      </BackLink>

      {loading ? (
        <Loading />
      ) : error ? (
        <Error onRetry={refetch} />
      ) : store ? (
        <>
          <StoreHeader>
            <StoreName>{store.name}</StoreName>
            <StoreLocation>{store.city}</StoreLocation>
          </StoreHeader>

          <SectionTitle>{t('discountedProducts')}</SectionTitle>

          {discounts.length > 0 ? (
            <Grid>
              {discounts.map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  store={store}
                />
              ))}
            </Grid>
          ) : (
            <EmptyState>
              <p>{t('noDiscounts')}</p>
            </EmptyState>
          )}
        </>
      ) : (
        <EmptyState>
          <p>{t('storeNotFound')}</p>
        </EmptyState>
      )}
    </Container>
  );
};

export default StoreDetail;
